const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;

  // Sunnah.com response
  if (d.hadith) {
    const text = d.hadith.body || d.hadith.text || '';
    const book = d.book?.title || d.collection || 'Hadith';
    const grade = d.hadith.grades?.[0]?.grade || '';
    const label = grade ? `${book} (${grade})` : book;
    if (text.length > 20) {
      results.push({ json: { raw_content: text, source: label, type: 'hadith' } });
    }
  }

  // Al-Quran Cloud response
  else if (d.data?.text) {
    const text = d.data.text;
    const surah = d.data.surah?.englishName || 'Al-Quran';
    const ayah = d.data.numberInSurah;
    const source = `Al-Quran — ${surah} (${ayah})`;
    if (text.length > 20) {
      results.push({ json: { raw_content: text, source, type: 'quran' } });
    }
  }

  // Webhook / Telegram push
  else if (d.body || d.text || d.content) {
    const text = d.body || d.text || d.content || '';
    if (text.length > 20) {
      results.push({ json: { raw_content: text, source: d.source || 'Telegram', type: 'manual' } });
    }
  }
}

return results;

const items = $input.all();
const results = [];

for (const item of items) {
  try {
    let text = item.json.text || item.json.content || '';
    text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    const parsed = JSON.parse(text);

    // SHA256 hash
    const encoder = new TextEncoder();
    const data = encoder.encode(parsed.content);
    const hashBuffer = await crypto.subtle.digest('SHA-256', data);
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    const hash = hashArray.map(b => b.toString(16).padStart(2, '0')).join('');

    const source = $('Normalize Input').item.json.source || 'Unknown';

    results.push({
      json: {
        content:      parsed.content,
        arabic_text:  parsed.arabic_text || null,
        meaning:      parsed.meaning || null,
        lesson:       parsed.lesson || null,
        source:       source,
        category:     parsed.category,
        language:     parsed.language || 'ms',
        content_hash: hash,
      }
    });
  } catch (e) {
    continue;
  }
}

return results;

const items = $input.all();
const results = { created: 0, duplicate: 0, error: 0 };

for (const item of items) {
  const status = item.json.statusCode || 200;
  if (status === 201) results.created++;
  else if (status === 409) results.duplicate++;
  else results.error++;
}

console.log(`Qalbu ingest: +${results.created} new | ${results.duplicate} dup | ${results.error} err`);
return [{ json: results }];
